     2→import { withAuthAndValidation } from "@/lib/api/with-auth";
     3→import { z } from "zod";
     4→import { createClient } from "redis";
     5→import {
     6→  sessionOutputChannel,
     7→  nodeEventsChannel,
     8→} from "@/lib/relay/redis-channels";
     9→import { db } from "@/lib/db/client";
    10→import { relaySession, relayNode } from "@/lib/db/schema";
    11→import { eq } from "drizzle-orm";
    12→import type { DaemonMessage } from "@/lib/relay/protocol";
    13→
    14→const eventsSchema = z.object({
    15→  nodeId: z.string().uuid(),
    16→  events: z.array(z.record(z.string(), z.unknown())),
    17→});
    18→
    19→/**
    20→ * POST /api/relay/events
    21→ *
    22→ * Receive events from relayd. Publishes to Redis for browser SSE subscribers.
    23→ * Handles session lifecycle events (created, ended) by updating DB.
    24→ */
    25→export const POST = withAuthAndValidation(
    26→  eventsSchema,
    27→  async (_request, { userId, body }) => {
    28→    const { nodeId, events } = body;
    29→
    30→    let redis: ReturnType<typeof createClient> | null = null;
    31→    try {
    32→      redis = createClient({
    33→        url: process.env.REDIS_URL || "redis://localhost:6379",
    34→      });
    35→      await redis.connect();
    36→
    37→      for (const raw of events) {
    38→        const event = raw as unknown as DaemonMessage;
    39→
    40→        switch (event.type) {
