// On (re)connect the server replays the last 500 buffered events before
// subscribing to live events, so we clear stale state on every open to
// avoid duplicates.
useEffect(() => {
  const es = new EventSource(`/api/relay/sessions/${id}/stream`);

  es.onopen = () => {
    setConnected(true);
