    async fn resize(&self, session_id: &Uuid, cols: u16, rows: u16) -> RelayResult<()> {
        let sessions = self.sessions.read().await;
        let handle = sessions
            .get(session_id)
            .ok_or_else(|| RelayError::SessionNotFound(session_id.to_string()))?;
        handle.resize(cols, rows)
    }
}

/// Dispatch a parsed [`ClaudeEvent`] to the daemon channel.
async fn handle_parsed_event(
    session_id: Uuid,
    line: &str,
    forward_tx: &mpsc::Sender<DaemonMessage>,
) {
    match parser::parse_line(line) {
        ClaudeEvent::ApprovalRequest {
            approval_id,
            capability,
            context,
        } => {
            debug!(
                session_id = %session_id,
                capability = %capability,
                "approval request detected"
            );
            let _ = forward_tx
                .send(DaemonMessage::ApprovalRequest {
                    session_id,
                    approval_id,
                    capability,
                    context,
                })
                .await;
        }
        ClaudeEvent::Result {
            cost_usd,
            duration_ms,
        } => {
            info!(
                session_id = %session_id,
                cost_usd = ?cost_usd,
                duration_ms = ?duration_ms,
                "claude session completed"
            );
            let _ = forward_tx
                .send(DaemonMessage::SessionEnded {
                    session_id,
                    reason: "completed".to_string(),
                })
                .await;
        }
        ClaudeEvent::SystemInit {
            model,
            session_id: sid,
            cwd,
        } => {
            debug!(
                session_id = %session_id,
                model = ?model,
                remote_sid = ?sid,
                cwd = ?cwd,
                "claude session initialized"
            );
        }
        ClaudeEvent::AssistantText { text } => {
            if !text.is_empty() {
                let _ = forward_tx
                    .send(DaemonMessage::AssistantMessage { session_id, text })
                    .await;
            }
        }
        ClaudeEvent::ToolUse { id, name, input } => {
            debug!(session_id = %session_id, tool = %name, "tool use");
            let _ = forward_tx
                .send(DaemonMessage::ToolEvent {
                    session_id,
                    tool_name: name,
                    tool_id: id,
                    input,
                })
                .await;
        }
        ClaudeEvent::ToolResult { .. } | ClaudeEvent::Raw(_) => {}
    }
}

/// Run git commands in `workdir` and assemble a [`DaemonMessage::WorkspaceStatus`].
///
/// All git invocations are best-effort — failures produce `None` / 0 values so
/// the caller always gets a usable (if sparse) status message.
async fn git_workspace_status(session_id: Uuid, workdir: &str) -> DaemonMessage {
    // Current branch
    let branch = Command::new("git")
        .args(["rev-parse", "--abbrev-ref", "HEAD"])
        .current_dir(workdir)
        .output()
        .await
        .ok()
        .and_then(|o| {
            if o.status.success() {
                String::from_utf8(o.stdout)
                    .ok()
                    .map(|s| s.trim().to_string())
                    .filter(|s| !s.is_empty() && s != "HEAD")
            } else {
                None
            }
        });

    // Modified (unstaged) + staged counts from `git status --porcelain`
    let (modified, staged) = Command::new("git")
        .args(["status", "--porcelain"])
        .current_dir(workdir)
        .output()
        .await
        .map(|o| {
            if !o.status.success() {
                return (0u32, 0u32);
            }
            let text = String::from_utf8_lossy(&o.stdout);
            let mut m = 0u32;
            let mut s = 0u32;
            for line in text.lines() {
                if line.len() < 2 {
                    continue;
                }
                let staged_char = line.chars().next().unwrap_or(' ');
                let unstaged_char = line.chars().nth(1).unwrap_or(' ');
                if staged_char != ' ' && staged_char != '?' {
                    s += 1;
                }
                if unstaged_char != ' ' && unstaged_char != '?' {
                    m += 1;
                }
            }
            (m, s)
        })
        .unwrap_or((0, 0));

    // Last commit: short hash + subject
    let last_commit = Command::new("git")
        .args(["log", "-1", "--format=%h %s"])
        .current_dir(workdir)
        .output()
        .await
        .ok()
        .and_then(|o| {
            if o.status.success() {
                String::from_utf8(o.stdout)
                    .ok()
                    .map(|s| s.trim().to_string())
                    .filter(|s| !s.is_empty())
            } else {
                None
            }
        });

    DaemonMessage::WorkspaceStatus {
        session_id,
        branch,
        modified,
        staged,
        last_commit,
    }
}

